def generate_all_info_from_primary_directions_only(log_dir = "/mnt/c/temp/", debugPrint=False): # Takes ~2 minutes.
    """ ### We keep this function anyway, even though its output is also hard-coded below this function so technically we no longer need it. ###
    Given lists of only primary directions, we recover for each of them the vertex that it finds and the optimum any STT achieves for it.
    This information is found when we 'enrich' the vertices, but was not saved initially.

    Because many primary directions result in the same vertex, and because vertices have a long representation
    (XZD variables, while a direction has only D "variables"), we keep a list of the vertices and for each direction just
    note its index in the corresponding list. """
    
    FULL_INFO_DICT,VERTEX_MAPPER = {},{}
    for k in PRIMARY_DIRECTIONS:
        if debugPrint: print (k,len(PRIMARY_DIRECTIONS[k]))
        searchTreeUtilities = SearchTreeUtilities(ALL_SMALL_GRAPHS[k[0]][k[1]])
        FULL_INFO_DICT[k],VERTEX_MAPPER[k] = [],[]
        
        # The LP to solve is always the same, so we compute the constraints once in advance.
        dict_ids_to_var_number = searchTreeUtilities.dict_ids_to_var_number
        inequalities,equalities,bounds = construct_constraints_primal(searchTreeUtilities, modes_vanilla)
        assert len(equalities) == 0
        inequalities_LP = inequalities + bounds # The bounds 'var >= 0' are also inequalities.
    
        for direction in PRIMARY_DIRECTIONS[k]:
            stt = searchTreeUtilities.find_best_search_tree(direction)
            lpvalue = scalar_product(stt,direction)
            assert int(lpvalue)==lpvalue # Integer since the primary directions are integer.

            objective_vector_of_LP = [0] * len(searchTreeUtilities.dict_ids_to_var_number)
            for i in range(1,searchTreeUtilities.n+1):
                objective_vector_of_LP[dict_ids_to_var_number[i] - 1] = direction[i-1] # Put it in the coordinates that corresponds to the depth vector D.
            result_as_dict = solve_LP(objective_vector_of_LP,inequalities_LP)
            vertex = clean_vector([result_as_dict[i] for i in result_as_dict])

            if vertex not in VERTEX_MAPPER[k]: VERTEX_MAPPER[k] += [vertex]
            idx = VERTEX_MAPPER[k].index(vertex)
            FULL_INFO_DICT[k] += [(idx,direction,lpvalue,idx)] # put idx twice temporarily, the first appearance is for sorting purposes.
        FULL_INFO_DICT[k] = sorted(FULL_INFO_DICT[k])
        FULL_INFO_DICT[k] = [i[1:] for i in FULL_INFO_DICT[k]] # remove the first (duplicate) element from each tuple.

    f = open(log_dir + os.sep + "PRIMARY_DIRECTIONS_FULL_INFO.txt",'w')
    f.write("PRIMARY_DIRECTIONS_FULL_INFO = " + str(FULL_INFO_DICT).replace("), (","),\n\t\t("))
    f.close()
    f = open(log_dir + os.sep + "MAPPER_INDEX_TO_FULL_VERTEX.txt",'w')
    f.write("MAPPER_INDEX_TO_FULL_VERTEX = " + str(VERTEX_MAPPER))
    f.close()
    print ("done",int(time.time()-start))
    

# 'PRIMARY_DIRECTIONS_FULL_INFO' maps from a topology's name to a list of triplets.
# Each triplet is composed of: (primary direction, value of best STT in this direction, index of the non-integer vertex that the LP finds).
