# 'NON_INT_VERTICES' is a more compact representation of 'MAPPER_INDEX_TO_FULL_VERTEX', where we only keep the depths (D-variables) per vertex. This dictionary is widely used in the code.
NON_INT_VERTICES = {}
for key in MAPPER_INDEX_TO_FULL_VERTEX:
    n = key[0]
    NON_INT_VERTICES[key] = [tuple(vertex[-n:]) for vertex in MAPPER_INDEX_TO_FULL_VERTEX[key]] # This is a hack that works only because the depths variables are the last ones. Otherwise, we would have needed an explicit mapping to the correct indices.

# 'NON_INT_VERTICES_REDUCED' is a dictionary where we de-duplicate the vertices in 'NON_INT_VERTICES' according to automorphism symmetries.
# The actual de-duplication happens in "STTLP-GraphsAndSTT.py" because at this point we do not have graphs and topologies to work with.
# 'NON_INT_VERTICES_REDUCED_WHOLE_REPRESENTATION' extends 'NON_INT_VERTICES_REDUCED' by having a list of tuples where each tuple is of the form:
# (1) a non-integer vertex from 'NON_INT_VERTICES_REDUCED' (D-only vector); (2) an extension of the vertex to a full (X,Z,D) representation of the vertex (usually unique, sometimes one of 2 or 3 possible extensions); (3) a corresponding primary direction (possibly one of several).
# So for now, just a place-holder names to be noted.
NON_INT_VERTICES_REDUCED = None # dedup_automorphism_vertices(vertex_dict = NON_INT_VERTICES)
NON_INT_VERTICES_REDUCED_WHOLE_REPRESENTATION = None # NON_INT_VERTICES_REDUCED_WHOLE_REPRESENTATION = extend_dict_of_depths_to_full_vertices(NON_INT_VERTICES_REDUCED,False)

